// 폴더 설정 출력 (setup 후 REPLACE_ME를 실제 ID로 교체)
const FOLDERS = [
  { folderName: '상품촬영',   gdId: '1L-La1gvSvA70G2bHGYzhyEwLRDD0fkrP', minioPath: 'products' },
  { folderName: '연출컷', gdId: '14hiqMyRhClC0kUi0JbD5HsBVcMO0y642', minioPath: 'content/styling' },
  { folderName: '썸네일소스', gdId: '1tul7XOF20JutfKXmxgPsJw5Iw07y-D07', minioPath: 'content/thumbnails' },
  { folderName: '클래스현장', gdId: '1Jsg-VKVoFlqgY5vDSUvionvmEK2uESIF', minioPath: 'class' },
  { folderName: '포장완성',   gdId: '1QZ-zel33BoXRnEMSO0C0uVHtnZ4zr9st', minioPath: 'internal/shipping' },
  { folderName: 'CS불량', gdId: '10tYWtzAq1Y9nG_ZKewAhNcsPgYj1SV5J', minioPath: 'internal/cs' },
  { folderName: '행사전시',   gdId: '1HxgzXMy-QwbVZ92X-m0_jcorGyAdFUXX', minioPath: 'content/events' },
  { folderName: '임시', gdId: '1AOESdS7EvagZ5_t7LqSR9isEYXTeOE1Y', minioPath: 'inbox' }
];
return FOLDERS.filter(f => f.gdId !== 'REPLACE_ME').map(f => ({ json: f }));

// HTTP 응답(파일 목록)과 원래 폴더 메타데이터를 합쳐서 개별 파일 아이템 생성
const httpItems = $input.all();
const allFiles = [];

for (let i = 0; i < httpItems.length; i++) {
  const files = httpItems[i].json.files || [];
  // 폴더 목록 노드의 같은 인덱스 아이템에서 메타데이터 가져오기
  let folderMeta;
  try {
    folderMeta = $('폴더 목록').all()[i].json;
  } catch(e) {
    continue;
  }

  for (const file of files) {
    allFiles.push({
      json: {
        fileId: file.id,
        fileName: file.name.replace(/[^a-zA-Z0-9가-힣._-]/g, '_'),
        originalName: file.name,
        mimeType: file.mimeType,
        fileSize: file.size || '0',
        folderName: folderMeta.folderName,
        gdId: folderMeta.gdId,
        minioPath: folderMeta.minioPath,
        hasFiles: true
      }
    });
  }
}

if (allFiles.length === 0) {
  return [{ json: { hasFiles: false, count: 0 } }];
}
return allFiles;

// 다운로드된 바이너리를 /tmp/에 저장 + 원래 메타데이터 복원
const fs = require('fs');

// 원래 메타데이터 복원 (파일 추출 노드에서)
let meta;
try {
  meta = $('파일 추출').item.json;
} catch(e) {
  meta = $input.item.json;
}

// 바이너리 데이터 가져오기 (방법 1: helpers, 방법 2: 직접 접근)
let binaryData;
const binaryKey = Object.keys($input.item.binary || {})[0];
if (binaryKey) {
  try {
    binaryData = await this.helpers.getBinaryDataBuffer($input.item.index || 0, binaryKey);
  } catch(e1) {
    try {
      binaryData = Buffer.from($input.item.binary[binaryKey].data, 'base64');
    } catch(e2) {
      return { json: { error: 'binary access failed: ' + e1.message + ' / ' + e2.message } };
    }
  }
} else {
  return { json: { error: 'no binary data found' } };
}

const tmpPath = '/tmp/n8n-img-' + meta.fileId;
fs.writeFileSync(tmpPath, binaryData);

return {
  json: {
    tmpPath,
    fileId: meta.fileId,
    fileName: meta.fileName,
    folderName: meta.folderName,
    minioPath: meta.minioPath,
    mimeType: meta.mimeType,
    fileSize: meta.fileSize
  }
};

// mc CLI로 MinIO에 업로드 (웹서빙 + 백업)
const { execSync } = require('child_process');
const mc = '/home/node/.n8n/mc';
const item = $input.item.json;
const today = new Date().toISOString().slice(0, 10);

try {
  // 웹서빙 버킷 업로드
  execSync(mc + ' cp ' + item.tmpPath + ' minio/images/' + item.minioPath + '/' + item.fileName, { timeout: 30000 });

  // 백업 버킷 업로드
  execSync(mc + ' cp ' + item.tmpPath + ' "minio/images/backup/' + today + '/' + item.folderName + '/' + item.fileName + '"', { timeout: 30000 });

  // 임시 파일 삭제
  require('fs').unlinkSync(item.tmpPath);

  return {
    json: {
      fileId: item.fileId,
      fileName: item.fileName,
      folderName: item.folderName,
      minioPath: item.minioPath,
      publicUrl: 'https://img.pressco21.com/images/' + item.minioPath + '/' + item.fileName,
      status: 'success'
    }
  };
} catch (err) {
  return { json: { error: err.message, fileName: item.fileName, status: 'failed' } };
}

const items = $input.all();
const summary = {};
let totalCount = 0;

for (const item of items) {
  const folder = item.json.folderName || '기타';
  summary[folder] = (summary[folder] || 0) + 1;
  totalCount++;
}

const lines = [];
for (const [folder, count] of Object.entries(summary)) {
  lines.push(folder + ': ' + count + '장');
}

const now = new Date();
const kst = new Date(now.getTime() + 9 * 60 * 60 * 1000);
const timeStr = kst.toISOString().slice(0, 16).replace('T', ' ');

const msg = '📸 사진 자동 업로드 완료\n\n' + lines.join('\n') + '\n\n🔗 https://img.pressco21.com\n⏰ ' + timeStr;

return [{ json: { message: msg, totalCount } }];
